import{c as t,Q as a,j as o,m as n}from"./chunks/framework.BPKcPtvA.js";const g=JSON.parse('{"title":"Managing Your Account","description":"","frontmatter":{},"headers":[],"relativePath":"guide/account/managing-your-account.md","filePath":"guide/account/managing-your-account.md","lastUpdated":1778862269000}'),r={name:"guide/account/managing-your-account.md"};function i(s,e,c,l,u,h){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="managing-your-account" tabindex="-1">Managing Your Account <a class="header-anchor" href="#managing-your-account" aria-label="Permalink to &quot;Managing Your Account&quot;">​</a></h1><p>The <strong>Account</strong> page is where you manage your own identity — your name, contact details, password, multi-factor authentication, notifications, and access. Every user has one, regardless of role.</p><p>You can reach the page from the user menu in the top right or, in the Customer Portal, from the <strong>Account</strong> entry in the sidebar.</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p>The page has a left column with editable sections and a right-hand <strong>Account Changes</strong> activity log that lists recent changes to your account (grouped by date).</p><h2 id="profile" tabindex="-1">Profile <a class="header-anchor" href="#profile" aria-label="Permalink to &quot;Profile&quot;">​</a></h2><p>Edit your personal information.</p><ul><li><strong>Username</strong> — read-only, set when your account was created.</li><li><strong>First Name</strong>, <strong>Last Name</strong>, <strong>Nickname</strong>, <strong>Display Name</strong> — all editable. Click <strong>Edit Profile</strong> to enter edit mode, change what you need, and click <strong>Save</strong>.</li></ul><p>Below the names is a <strong>Contact Information</strong> sub-section:</p><ul><li><strong>Email</strong> — your primary email, shown with a verified / unverified badge. If unverified, a <strong>Resend verification</strong> action is available.</li><li><strong>Phone</strong> — optional. Add, edit, remove, and verify with the buttons provided. A verification SMS is sent when you click Verify.</li></ul><h2 id="user-attributes-customer-users-only" tabindex="-1">User Attributes (customer users only) <a class="header-anchor" href="#user-attributes-customer-users-only" aria-label="Permalink to &quot;User Attributes (customer users only)&quot;">​</a></h2><p>If your customer has defined custom user attributes (company, department, cost centre, etc.), they appear here. If you belong to multiple customer organisations, an organisation switcher lets you fill the attributes for each one separately.</p><p>Edit the fields and click <strong>Save Attributes</strong> to persist.</p><h2 id="password" tabindex="-1">Password <a class="header-anchor" href="#password" aria-label="Permalink to &quot;Password&quot;">​</a></h2><p>The Console does not let you change your password inline — passwords are managed by the underlying identity provider. Use the <strong>Send Password Reset Email</strong> button. A reset link is emailed to your address. After clicking the button there is a one-minute cooldown before you can request another.</p><h2 id="multi-factor-authentication" tabindex="-1">Multi-Factor Authentication <a class="header-anchor" href="#multi-factor-authentication" aria-label="Permalink to &quot;Multi-Factor Authentication&quot;">​</a></h2><p>See <a href="./multi-factor-authentication">Multi-Factor Authentication</a> for the full details. From this section you can:</p><ul><li>See which MFA methods are currently enabled on your account.</li><li><strong>Set up Authenticator App</strong> (TOTP).</li><li><strong>Enable Email OTP</strong>.</li><li><strong>Add Passkey</strong>.</li><li>Remove any method (a confirmation modal makes sure you do not lock yourself out).</li></ul><h2 id="notifications-internal-operators-only" tabindex="-1">Notifications (internal operators only) <a class="header-anchor" href="#notifications-internal-operators-only" aria-label="Permalink to &quot;Notifications (internal operators only)&quot;">​</a></h2><p>Operators have access to a Notifications panel that controls which event categories — Operations, Discrepancies, Billing, Infrastructure, General — send you notifications, and on which channels (in-app and email).</p><p>Each subscription has two toggles, one per channel. Subscriptions marked <strong>Required</strong> are mandatory for your role and cannot be turned off.</p><p>Customer portal users do not see this panel — their notifications are managed at the customer level.</p><h2 id="tenant-access" tabindex="-1">Tenant Access <a class="header-anchor" href="#tenant-access" aria-label="Permalink to &quot;Tenant Access&quot;">​</a></h2><p>A read-only list of the tenants you have been assigned to, with the role you hold in each. To add or change assignments, ask a customer admin.</p><h2 id="identity-provider-links" tabindex="-1">Identity Provider Links <a class="header-anchor" href="#identity-provider-links" aria-label="Permalink to &quot;Identity Provider Links&quot;">​</a></h2><p>A read-only list of external identity providers (Google, Microsoft, custom OIDC) linked to your account. Useful if you sign in via SSO and need to confirm which external account is mapped to your Console identity.</p><h2 id="account-changes-right-column" tabindex="-1">Account Changes (right column) <a class="header-anchor" href="#account-changes-right-column" aria-label="Permalink to &quot;Account Changes (right column)&quot;">​</a></h2><p>A reverse-chronological audit of changes to your own account — what changed, when, and who made the change. Useful for spotting unauthorised modifications.</p><p>Operator-driven changes show the operator&#39;s initials. System events show a generic system marker.</p>',29)])])}const p=t(r,[["render",i]]);export{g as __pageData,p as default};
